# Basic decorator to measure execution time
import time

def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f"{func.__name__} took {end - start:.2f} seconds")
        return result
    return wrapper

@timer
def slow_function():
    time.sleep(2)
    return "Done"

print(slow_function())  # Output: slow_function took 2.00 seconds\nDone

# Decorator with arguments
def repeat(n):
    def decorator(func):
        def wrapper(*args, **kwargs):
            results = []
            for _ in range(n):
                results.append(func(*args, **kwargs))
            return results
        return wrapper
    return decorator

@repeat(3)
def greet(name):
    return f"Hello, {name}!"

print(greet("Alice"))  # Output: ['Hello, Alice!', 'Hello, Alice!', 'Hello, Alice!']

# Multiple decorators
@timer
@repeat(2)
def process(data):
    return data.upper()

print(process("hello"))  # Output: process took 0.00 seconds\n['HELLO', 'HELLO']
